import { describe, it, expect } from 'vitest';
import { PollingScheduler, PollingState } from '../polling-scheduler';
import { take, toArray } from 'rxjs/operators';
import { ConfigSchema } from '../../types/config';

describe('PollingScheduler', () => {
  it('defaults to IDLE interval', async () => {
    const scheduler = new PollingScheduler();
    const config = ConfigSchema.parse({});
    scheduler.setConfig(config);

    const result = await scheduler.interval$.pipe(take(1)).toPromise();
    expect(result).toBe(30000); // default idle
  });

  it('adjusts interval on state change', async () => {
    const scheduler = new PollingScheduler();
    const config = ConfigSchema.parse({});
    scheduler.setConfig(config);

    const intervals: number[] = [];
    const sub = scheduler.interval$.subscribe(v => intervals.push(v));

    scheduler.setState(PollingState.ACTIVE);
    scheduler.setState(PollingState.CRITICAL);
    scheduler.setState(PollingState.OFFLINE);

    sub.unsubscribe();

    // IDLE -> ACTIVE -> CRITICAL -> OFFLINE
    expect(intervals).toEqual([30000, 5000, 2000, 60000]);
  });
});

import { Observable, timer } from 'rxjs';

/**
 * Generates an exponential backoff sequence with jitter.
 * @param initialDelayMs The starting delay
 * @param maxDelayMs The maximum delay
 * @param jitterFactor Randomizer multiplier (0.0 - 1.0)
 */
export function createBackoffTimer(
  initialDelayMs: number = 1000,
  maxDelayMs: number = 60000,
  jitterFactor: number = 0.2
): Observable<number> {
  return new Observable<number>((subscriber) => {
    let currentDelay = initialDelayMs;
    let isActive = true;

    const scheduleNext = () => {
      if (!isActive) return;

      const jitter = 1 + (Math.random() * 2 - 1) * jitterFactor; // 0.8 to 1.2 for factor 0.2
      const actualDelay = Math.floor(currentDelay * jitter);

      subscriber.next(actualDelay);

      currentDelay = Math.min(currentDelay * 2, maxDelayMs);

      setTimeout(scheduleNext, actualDelay);
    };

    scheduleNext();

    return () => {
      isActive = false;
    };
  });
}

import { filter, switchMap, tap, catchError, of, Subscription, Observable } from 'rxjs';
import { PollingScheduler, PollingState } from '../polling/polling-scheduler';
import { SourceRegistry } from '../acquisition/source-registry';
import { updateQuotaState } from './quota-state';
import { log } from '../../util/logger';
import { Config } from '../types/config';
import { SourceReading } from '../types/quota';

export class QuotaStreamTopology {
  private subscription?: Subscription;
  private readonly scheduler = new PollingScheduler();

  constructor(
    private readonly sources: SourceRegistry,
    initialConfig: Config
  ) {
    this.scheduler.setConfig(initialConfig);
  }

  public updateConfig(config: Config) {
    this.scheduler.setConfig(config);
  }

  public setPollingState(state: PollingState) {
    this.scheduler.setState(state);
  }

  public start(): void {
    if (this.subscription) return;

    this.subscription = this.scheduler.tick$
      .pipe(
        filter(() => this.scheduler.getCurrentState() !== PollingState.OFFLINE),
        switchMap(() => this.fetchAllSources()),
        tap(readings => {
          if (readings.length > 0) {
            updateQuotaState(readings);
            this.evaluateCriticalThreshold(readings);
          }
        }),
        catchError(err => {
          log.error('Pipeline error', err);
          return of([]);
        })
      )
      .subscribe();

    log.info('Quota stream topology started.');
  }

  public stop(): void {
    this.subscription?.unsubscribe();
    this.subscription = undefined;
    log.info('Quota stream topology stopped.');
  }

  private async fetchAllSources(): Promise<SourceReading[]> {
    const activeSources = this.sources.getHealthySources();
    if (activeSources.length === 0) return [];

    const promises = activeSources.map(async src => {
      try {
        const result = await src.fetch();
        if (result) {
          this.sources.recordSuccess(src.id);
          return result;
        }
      } catch (e) {
        log.warn(`Source ${src.id} failed fetch:`, e);
      }
      this.sources.recordFailure(src.id);
      return null;
    });

    const results = await Promise.all(promises);
    return results.filter((r): r is SourceReading => r !== null);
  }

  private evaluateCriticalThreshold(readings: SourceReading[]) {
    // If any reading drops below a hypothetical critical limit (handled in actual alerts module),
    // we could flip state to CRITICAL here. For Phase 1 we will keep this simple.
    const isCritical = readings.some(r => r.remainingPercent <= 10);
    if (isCritical && this.scheduler.getCurrentState() !== PollingState.CRITICAL) {
      this.scheduler.setState(PollingState.CRITICAL);
    } else if (!isCritical && this.scheduler.getCurrentState() === PollingState.CRITICAL) {
      this.scheduler.setState(PollingState.ACTIVE); // fallback to active
    }
  }
}

import * as vscode from 'vscode';
import { initI18n, t } from './i18n/setup';
import { detectConnection } from './platform/connection/detector';
import { connectionState$, ConnectionStatus } from './platform/connection/connection-state';
import { log } from './util/logger';
import { DisposableStore } from './util/disposable';
import { ConfigSchema } from './core/types/config';

export async function activate(context: vscode.ExtensionContext) {
  const disposable = new DisposableStore();

  try {
    log.init(context);
    log.info('K1 Antigravity Monitor activating...');

    await initI18n();

    // Default configuration parsing
    const config = ConfigSchema.parse({
      pollingIntervalIdle: 30000,
      pollingIntervalActive: 5000,
      thresholdWarning: 20,
      thresholdCritical: 10,
      showModel: 'autoLowest',
      pinnedModel: '',
      animationEnabled: true,
      antigravityPort: 13337,
    });

    const connectionResult = await detectConnection();

    if (connectionResult) {
      log.info(`Antigravity detected on port ${connectionResult.port}`);
      connectionState$.next({
        status: ConnectionStatus.CONNECTED,
        port: connectionResult.port,
        token: connectionResult.token,
      });
    } else {
      log.warn('Could not auto-detect Antigravity.');
      connectionState$.next({ status: ConnectionStatus.DISCONNECTED });
    }

    // Register Phase 1 placeholder commands required by package.json
    disposable.add(vscode.commands.registerCommand('k1.refreshQuota', () => {
      vscode.window.showInformationMessage(t('commands.refreshQuota.title'));
    }));
    disposable.add(vscode.commands.registerCommand('k1.switchModel', () => {
      vscode.window.showInformationMessage(t('commands.switchModel.title'));
    }));
    disposable.add(vscode.commands.registerCommand('k1.togglePanel', () => {
      vscode.window.showInformationMessage(t('commands.togglePanel.title'));
    }));
    disposable.add(vscode.commands.registerCommand('k1.showDiagnostics', () => {
      vscode.window.showInformationMessage(t('commands.showDiagnostics.title'));
    }));

    context.subscriptions.push(disposable);
    log.info('K1 Antigravity Monitor activated successfully.');
  } catch (e) {
    if (e instanceof Error) {
      log.error(`Activation failed: ${e.message}`, e.stack);
    }
    vscode.window.showErrorMessage(t('extension.activationFailed'));
  }
}

export function deactivate() {
  // Handled by DisposableStore
}

import i18next from 'i18next';
import en from './locales/en.json';
import { I18nKey } from './keys';

export async function initI18n(): Promise<void> {
  await i18next.init({
    lng: 'en',
    fallbackLng: 'en',
    resources: {
      en: { translation: en },
    },
    interpolation: { escapeValue: false },
  });
}

export function t(key: I18nKey, options?: Record<string, unknown>): string {
  return i18next.t(key, options);
}
